8. Update **wwwroot/service-worker.published.js** with cache-first strategy:
```javascript
// Site Inspector - Service Worker (Published)
const CACHE_NAME = 'site-inspector-cache-v1';

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => {
            return fetch('service-worker-assets.js')
                .then(response => response.text())
                .then(text => {
                    const assets = JSON.parse(text.replace('self.assetsManifest = ', '').replace(';', ''));
                    const requests = assets.assets.map(asset => new Request(asset.url));
                    return Promise.all(requests.map(req =>
                        cache.add(req).catch(() => { /* skip failures */ })
                    ));
                });
        })
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    if (event.request.method !== 'GET') return;

    event.respondWith(
        caches.match(event.request).then(cached => {
            if (cached) return cached;
            return fetch(event.request).then(response => {
                if (response.ok) {
                    const clone = response.clone();
                    caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                }
                return response;
            }).catch(() => cached);
        })
    );
});
