window.indexedDb = {
    db: null,

    initialize: function () {
        return new Promise((resolve, reject) => {
            if (this.db) { resolve(); return; }
            const request = window.indexedDB.open('SiteInspectorDb', 1);

            request.onupgradeneeded = (event) => {
                const db = event.target.result;

                if (!db.objectStoreNames.contains('inspections')) {
                    const inspStore = db.createObjectStore('inspections', { keyPath: 'id' });
                    inspStore.createIndex('syncStatus', 'syncStatus', { unique: false });
                    inspStore.createIndex('date', 'date', { unique: false });
                }

                if (!db.objectStoreNames.contains('checklistItems')) {
                    const itemStore = db.createObjectStore('checklistItems', { keyPath: 'id' });
                    itemStore.createIndex('inspectionId', 'inspectionId', { unique: false });
                }

                if (!db.objectStoreNames.contains('photos')) {
                    const photoStore = db.createObjectStore('photos', { keyPath: 'id' });
                    photoStore.createIndex('inspectionId', 'inspectionId', { unique: false });
                    photoStore.createIndex('checklistItemId', 'checklistItemId', { unique: false });
                }
            };

            request.onsuccess = (event) => {
                this.db = event.target.result;
                resolve();
            };

            request.onerror = (event) => {
                reject(event.target.error);
            };
        });
    },

    // Inspections
    saveInspection: function (inspection) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            store.put(inspection);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getAllInspections: function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.getAll();
            request.onsuccess = () => {
                const results = request.result.sort((a, b) => new Date(b.date) - new Date(a.date));
                resolve(results);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getInspection: function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteInspection: function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            store.delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPendingInspections: function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const index = store.index('syncStatus');
            const request = index.getAll('Pending');
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    updateSyncStatus: function (inspectionId, status) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            const getReq = store.get(inspectionId);
            getReq.onsuccess = () => {
                const inspection = getReq.result;
                if (inspection) {
                    inspection.syncStatus = status;
                    store.put(inspection);
                }
                tx.oncomplete = () => resolve();
            };
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    // Checklist Items
    saveChecklistItem: function (item) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('checklistItems', 'readwrite');
            const store = tx.objectStore('checklistItems');
            store.put(item);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getChecklistItems: function (inspectionId) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('checklistItems', 'readonly');
            const store = tx.objectStore('checklistItems');
            const index = store.index('inspectionId');
            const request = index.getAll(inspectionId);
            request.onsuccess = () => {
                const results = (request.result || []).sort((a, b) => a.order - b.order);
                resolve(results);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteChecklistItemsForInspection: function (inspectionId) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('checklistItems', 'readwrite');
            const store = tx.objectStore('checklistItems');
            const index = store.index('inspectionId');
            const request = index.getAllKeys(inspectionId);
            request.onsuccess = () => {
                const keys = request.result;
                keys.forEach(key => store.delete(key));
                tx.oncomplete = () => resolve();
            };
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    // Photos
    savePhoto: function (photo) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('photos', 'readwrite');
            const store = tx.objectStore('photos');
            store.put(photo);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPhotosForInspection: function (inspectionId) {
