                Next →
            </button>
        }
    </div>
}
else if (loading)
{
    <p>Loading checklist...</p>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? inspection;
    private List<ChecklistItem> items = new();
    private int currentIndex;
    private ChecklistItem? currentItem => items.Count > currentIndex ? items[currentIndex] : null;
    private bool showNotes;
    private bool loading = true;
    private int photoCount;
    private int completedCount => items.Count(i => i.Result != CheckResult.NotChecked);
    private int ProgressPercent => items.Count > 0 ? (int)((double)completedCount / items.Count * 100) : 0;

    protected override async Task OnInitializedAsync()
    {
        inspection = await DbService.GetInspectionAsync(InspectionId);
        items = await DbService.GetChecklistItemsAsync(InspectionId);
        await LoadPhotoCount();
        loading = false;
    }

    private async Task LoadPhotoCount()
    {
        if (currentItem != null)
        {
            var photos = await DbService.GetPhotosForItemAsync(currentItem.Id);
            photoCount = photos.Count;
        }
    }

    private async Task SetResult(CheckResult result)
    {
        if (currentItem == null) return;

        // Immediate UI update
        currentItem.Result = result;

        // Save async
        await DbService.SaveChecklistItemAsync(currentItem);
        await UpdateInspectionProgress();
    }

    private async Task SaveCurrentItem()
    {
        if (currentItem != null)
        {
            await DbService.SaveChecklistItemAsync(currentItem);
        }
    }

    private async Task Next()
    {
        await SaveCurrentItem();
        if (currentIndex < items.Count - 1)
        {
            currentIndex++;
            showNotes = !string.IsNullOrEmpty(currentItem?.Notes);
            await LoadPhotoCount();
        }
    }

    private async Task Previous()
    {
        await SaveCurrentItem();
        if (currentIndex > 0)
        {
            currentIndex--;
            showNotes = !string.IsNullOrEmpty(currentItem?.Notes);
            await LoadPhotoCount();
        }
    }

    private void ToggleNotes()
    {
        showNotes = !showNotes;
    }

    private void GoToPhotos()
    {
        if (currentItem != null)
        {
            Navigation.NavigateTo($"/photos/{InspectionId}/{currentItem.Id}");
        }
    }

    private async Task FinishInspection()
    {
        await SaveCurrentItem();
        if (inspection != null)
        {
            inspection.Status = "Complete";
            inspection.CompletedItems = completedCount;
            await DbService.SaveInspectionAsync(inspection);
        }
        Navigation.NavigateTo($"/inspection/{InspectionId}");
    }

    private async Task UpdateInspectionProgress()
    {
        if (inspection != null)
        {
            inspection.CompletedItems = completedCount;
            await DbService.SaveInspectionAsync(inspection);
        }
    }
}
