14. Add to **wwwroot/js/indexedDb.js** (append this function at the end, outside the indexedDb object, as a global):

Actually, add a `readFileAsBase64` function. Create a separate small snippet or add it to a section of the indexedDb.js file. Better: add it to connectivity.js or create inline in index.html. Let's add it at the end of indexedDb.js outside the object:

```javascript
// Add this AFTER the closing of the window.indexedDb object
window.readFileAsBase64 = function (inputElement) {
    return new Promise((resolve) => {
        const file = inputElement.files && inputElement.files[0];
        if (!file) { resolve(null); return; }
        const reader = new FileReader();
        reader.onload = () => {
            const base64 = reader.result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = () => resolve(null);
        reader.readAsDataURL(file);
    });
};
```

