namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _dbService;
    private readonly HttpClient _httpClient;
    private readonly IJSRuntime _jsRuntime;
    private DotNetObjectReference<SyncService>? _objRef;

    public bool IsOnline { get; private set; } = true;
    public int PendingCount { get; private set; }
    public bool IsSyncing { get; private set; }

    public event Action? OnStatusChanged;

    public SyncService(IndexedDbService dbService, HttpClient httpClient, IJSRuntime jsRuntime)
    {
        _dbService = dbService;
        _httpClient = httpClient;
        _jsRuntime = jsRuntime;
    }

    public async Task InitializeAsync()
    {
        _objRef = DotNetObjectReference.Create(this);
        await _jsRuntime.InvokeVoidAsync("connectivity.initialize", _objRef);
        IsOnline = await _jsRuntime.InvokeAsync<bool>("connectivity.isOnline");
        await UpdatePendingCountAsync();
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnStatusChanged?.Invoke();

        if (isOnline)
        {
            await SyncPendingAsync();
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        var pending = await _dbService.GetPendingInspectionsAsync();
        PendingCount = pending.Count;
        OnStatusChanged?.Invoke();
    }

    public async Task SyncPendingAsync()
    {
        if (IsSyncing || !IsOnline) return;

        IsSyncing = true;
        OnStatusChanged?.Invoke();

        try
        {
            var pending = await _dbService.GetPendingInspectionsAsync();
            foreach (var inspection in pending)
            {
                try
                {
                    // Mock sync - in production this would POST to a real API
                    await Task.Delay(500); // Simulate network
                    await _dbService.UpdateSyncStatusAsync(inspection.Id, SyncStatus.Synced);
                }
                catch
                {
                    await _dbService.UpdateSyncStatusAsync(inspection.Id, SyncStatus.Failed);
                }
            }
        }
        finally
        {
            IsSyncing = false;
            await UpdatePendingCountAsync();
        }
    }

    public void Dispose()
    {
        _objRef?.Dispose();
    }
}

