@code {
    private string siteName = "";
    private string inspectorName = "";
    private string notes = "";
    private ChecklistTemplate? selectedTemplate;
    private List<ChecklistTemplate> templates = new();

    private bool CanStart => !string.IsNullOrWhiteSpace(siteName)
        && !string.IsNullOrWhiteSpace(inspectorName)
        && selectedTemplate != null;

    protected override void OnInitialized()
    {
        templates = TemplateService.GetTemplates();
    }

    private void SelectTemplate(ChecklistTemplate template)
    {
        selectedTemplate = template;
    }

    private async Task StartInspection()
    {
        if (!CanStart || selectedTemplate == null) return;

        var inspection = new Inspection
        {
            SiteId = Guid.NewGuid().ToString(),
            SiteName = siteName,
            InspectorName = inspectorName,
            Notes = notes,
            ChecklistType = selectedTemplate.Name,
            TotalItems = selectedTemplate.Items.Count,
            CompletedItems = 0
        };

        await DbService.SaveInspectionAsync(inspection);

        foreach (var templateItem in selectedTemplate.Items)
        {
            var item = new ChecklistItem
            {
                InspectionId = inspection.Id,
                Category = templateItem.Category,
                Description = templateItem.Description,
                Order = templateItem.Order
            };
            await DbService.SaveChecklistItemAsync(item);
        }

        Navigation.NavigateTo($"/checklist/{inspection.Id}");
    }
}

