@code {
    [Parameter] public string InspectionId { get; set; } = "";
    [Parameter] public string ChecklistItemId { get; set; } = "";

    private List<InspectionPhoto> photos = new();
    private string itemDescription = "";
    private ElementReference fileInput;
    private ElementReference galleryInput;

    protected override async Task OnInitializedAsync()
    {
        photos = await DbService.GetPhotosForItemAsync(ChecklistItemId);
        var items = await DbService.GetChecklistItemsAsync(InspectionId);
        var item = items.FirstOrDefault(i => i.Id == ChecklistItemId);
        itemDescription = item?.Description ?? "";
    }

    private async Task OnFileSelected(ChangeEventArgs e)
    {
        var base64 = await JS.InvokeAsync<string>("readFileAsBase64", fileInput);
        if (string.IsNullOrEmpty(base64))
        {
            base64 = await JS.InvokeAsync<string>("readFileAsBase64", galleryInput);
        }

        if (!string.IsNullOrEmpty(base64))
        {
            var photo = new InspectionPhoto
            {
                InspectionId = InspectionId,
                ChecklistItemId = ChecklistItemId,
