+@inject NavigationManager Navigation
+
+<div class="page-header">
+    <h1 class="page-title">Photos</h1>
+    <p class="page-subtitle">@itemDescription</p>
+</div>
+
+<div class="form-group">
+    <label class="photo-capture-btn" for="camera-input">
+        📷 Capture Photo
+    </label>
+    <input id="camera-input" type="file" accept="image/*" capture="environment"
+           style="display:none" @ref="fileInput" @onchange="OnFileSelected" />
+</div>
+
+<div class="form-group">
+    <label class="photo-capture-btn" for="gallery-input">
+        🖼️ Choose from Gallery
+    </label>
+    <input id="gallery-input" type="file" accept="image/*"
+           style="display:none" @ref="galleryInput" @onchange="OnFileSelected" />
+</div>
+
+@if (photos.Count > 0)
+{
+    <div class="photo-grid">
+        @foreach (var photo in photos)
+        {
+            <div class="photo-thumb">
+                <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
+            </div>
+        }
+    </div>
+}
+else
+{
+    <div class="empty-state">
+        <div class="empty-icon">📷</div>
+        <div class="empty-title">No photos yet</div>
+        <div class="empty-subtitle">Capture or upload photos for this item</div>
+    </div>
+}
+
+<button class="btn btn-primary btn-block" style="margin-top:24px" @onclick="GoBack">
+    ← Back to Checklist
+</button>
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = "";
+    [Parameter] public string ChecklistItemId { get; set; } = "";
+
+    private List<InspectionPhoto> photos = new();
+    private string itemDescription = "";
+    private ElementReference fileInput;
+    private ElementReference galleryInput;
+
+    protected override async Task OnInitializedAsync()
+    {
+        photos = await DbService.GetPhotosForItemAsync(ChecklistItemId);
+        var items = await DbService.GetChecklistItemsAsync(InspectionId);
+        var item = items.FirstOrDefault(i => i.Id == ChecklistItemId);
+        itemDescription = item?.Description ?? "";
+    }
+
+    private async Task OnFileSelected(ChangeEventArgs e)
+    {
+        var base64 = await JS.InvokeAsync<string>("readFileAsBase64", fileInput);
+        if (string.IsNullOrEmpty(base64))
+        {
+            base64 = await JS.InvokeAsync<string>("readFileAsBase64", galleryInput);
+        }
+
+        if (!string.IsNullOrEmpty(base64))
+        {
+            var photo = new InspectionPhoto
+            {
+                InspectionId = InspectionId,
+                ChecklistItemId = ChecklistItemId,
+                Base64Data = base64,
+                Caption = $"Photo {photos.Count + 1}"
+            };
+
+            await DbService.SavePhotoAsync(photo);
+            photos.Add(photo);
+        }
+    }
+
+    private void GoBack()
+    {
+        Navigation.NavigateTo($"/checklist/{InspectionId}");
+    }
+}
+

