@inherits LayoutComponentBase
@inject SiteInspector.Services.SyncService SyncService

<div class="app-layout">
    <div class="status-bar">
        <div class="status-indicator">
            <span class="status-dot @(SyncService.IsOnline ? "online" : "offline")"></span>
            <span>@(SyncService.IsOnline ? "Online" : "Offline")</span>
        </div>
        @if (SyncService.IsSyncing)
        {
            <div class="sync-badge syncing">⟳ Syncing...</div>
        }
        else if (SyncService.PendingCount > 0)
        {
            <div class="sync-badge">@SyncService.PendingCount pending</div>
        }
    </div>

    <main class="page-content">
        @Body
    </main>

    <nav class="bottom-nav">
        <a href="/" class="nav-item @(IsActive("/"))">
            <span class="nav-icon">🏠</span>
            <span>Home</span>
        </a>
        <a href="/new" class="nav-item @(IsActive("/new"))">
            <span class="nav-icon">➕</span>
            <span>New</span>
        </a>
        <button class="nav-item" @onclick="SyncNow">
            <span class="nav-icon">🔄</span>
            <span>Sync</span>
        </button>
    </nav>
</div>

@code {
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    protected override void OnInitialized()
    {
        SyncService.OnStatusChanged += StateHasChanged;
        Navigation.LocationChanged += (_, _) => StateHasChanged();
    }

    private string IsActive(string path)
    {
        var uri = Navigation.ToBaseRelativePath(Navigation.Uri);
        if (path == "/" && string.IsNullOrEmpty(uri)) return "active";
        if (path != "/" && ("/" + uri).StartsWith(path)) return "active";
        return "";
    }

    private async Task SyncNow()
    {
        await SyncService.SyncPendingAsync();
    }
}
