78.     private int currentIndex;
79.     private ChecklistItem? currentItem => items.Count > currentIndex ? items[currentIndex] : null;
80.     private bool showNotes;
81.     private bool loading = true;
82.     private int photoCount;
83.     private int completedCount => items.Count(i => i.Result != CheckResult.NotChecked);
84.     private int ProgressPercent => items.Count > 0 ? (int)((double)completedCount / items.Count * 100) : 0;
85. 
86.     protected override async Task OnInitializedAsync()
87.     {
88.         inspection = await DbService.GetInspectionAsync(InspectionId);
89.         items = await DbService.GetChecklistItemsAsync(InspectionId);
90.         await LoadPhotoCount();
91.         loading = false;
92.     }
93. 
94.     private async Task LoadPhotoCount()
95.     {
96.         if (currentItem != null)
97.         {
98.             var photos = await DbService.GetPhotosForItemAsync(currentItem.Id);
99.             photoCount = photos.Count;
100.         }
101.     }
102. 
