104.     {
105.         if (currentItem == null) return;
106. 
107.         currentItem.Result = result;
108. 
109.         await DbService.SaveChecklistItemAsync(currentItem);
110.         await UpdateInspectionProgress();
111.     }
112. 
113.     private async Task SaveCurrentItem()
114.     {
115.         if (currentItem != null)
116.         {
117.             await DbService.SaveChecklistItemAsync(currentItem);
118.         }
119.     }
120. 
121.     private async Task Next()
122.     {
123.         await SaveCurrentItem();
124.         if (currentIndex < items.Count - 1)
125.         {
126.             currentIndex++;
127.             showNotes = !string.IsNullOrEmpty(currentItem?.Notes);
128.             await LoadPhotoCount();
129.         }
130.     }
131. 
