157.     {
158.         await SaveCurrentItem();
159.         if (inspection != null)
160.         {
161.             inspection.Status = "Complete";
162.             inspection.CompletedItems = completedCount;
163.             await DbService.SaveInspectionAsync(inspection);
164.         }
165.         Navigation.NavigateTo($"/inspection/{InspectionId}");
166.     }
