 .card {
     background: var(--surface);
     border-radius: var(--radius);
     box-shadow: var(--shadow);
     padding: 16px;
     margin-bottom: 12px;
 }

 .card:active {
     transform: scale(0.98);
     transition: transform 0.1s;
 }

 .card-header {
     display: flex;
     align-items: center;
     justify-content: space-between;
     margin-bottom: 8px;
 }

 .card-title {
     font-size: 1rem;
     font-weight: 600;
     color: var(--text);
 }

 .card-subtitle {
     font-size: 0.85rem;
     color: var(--text-secondary);
 }

 .card-badge {
     padding: 3px 8px;
     border-radius: 6px;
     font-size: 0.7rem;
     font-weight: 600;
     text-transform: uppercase;
 }

 .badge-pending { background: var(--warning-light); color: var(--warning); }
 .badge-synced { background: var(--success-light); color: var(--success); }
 .badge-progress { background: #dbeafe; color: var(--primary); }
 .badge-complete { background: var(--success-light); color: var(--success); }

 /* Buttons */
 .btn {
     display: inline-flex;
     align-items: center;
     justify-content: center;
     min-height: var(--touch-target);
     min-width: var(--touch-target);
     padding: 12px 24px;
     border: none;
     border-radius: var(--radius);
     font-size: 1rem;
     font-weight: 600;
     cursor: pointer;
     transition: transform 0.1s, opacity 0.15s;
     text-decoration: none;
     gap: 8px;
 }

 .btn:active {
     transform: scale(0.95);
 }

 .btn-primary {
     background: var(--primary);
     color: white;
 }

 .btn-success {
     background: var(--success);
     color: white;
 }

 .btn-danger {
     background: var(--danger);
     color: white;
 }

 .btn-gray {
     background: var(--gray);
     color: white;
 }

 .btn-outline {
     background: transparent;
     border: 2px solid var(--gray-light);
     color: var(--text);
 }

 .btn-block {
     width: 100%;
 }

 .btn-lg {
     min-height: 56px;
     font-size: 1.1rem;
     padding: 16px 32px;
 }

 /* Checklist Buttons */
 .check-buttons {
     display: grid;
     grid-template-columns: 1fr 1fr 1fr;
     gap: 8px;
     margin-top: 12px;
 }

 .check-btn {
     display: flex;
     align-items: center;
     justify-content: center;
     min-height: 56px;
     border: 3px solid transparent;
     border-radius: var(--radius);
     font-size: 0.9rem;
     font-weight: 700;
     cursor: pointer;
     transition: transform 0.1s, border-color 0.15s;
     text-transform: uppercase;
 }

 .check-btn:active {
     transform: scale(0.93);
 }

 .check-btn.pass {
     background: var(--success-light);
     color: var(--success);
     border-color: transparent;
 }

 .check-btn.pass.selected {
     background: var(--success);
     color: white;
     border-color: var(--success);
 }

 .check-btn.fail {
     background: var(--danger-light);
     color: var(--danger);
     border-color: transparent;
 }

 .check-btn.fail.selected {
     background: var(--danger);
     color: white;
     border-color: var(--danger);
 }

 .check-btn.na {
     background: var(--gray-light);
     color: var(--gray);
     border-color: transparent;
 }

 .check-btn.na.selected {
     background: var(--gray);
     color: white;
     border-color: var(--gray);
 }

 /* Form elements */
 .form-group {
     margin-bottom: 16px;
 }

 .form-label {
     display: block;
     font-size: 0.85rem;
     font-weight: 600;
     color: var(--text-secondary);
     margin-bottom: 6px;
 }

 .form-input, .form-select, .form-textarea {
     width: 100%;
     min-height: var(--touch-target);
     padding: 12px 16px;
     border: 2px solid var(--gray-light);
     border-radius: var(--radius);
     font-size: 1rem;
     color: var(--text);
     background: var(--surface);
     transition: border-color 0.15s;
 }

 .form-input:focus, .form-select:focus, .form-textarea:focus {
     outline: none;
     border-color: var(--primary);
 }

 .form-textarea {
     min-height: 80px;
     resize: vertical;
 }

 /* Progress */
 .progress-bar {
     height: 6px;
     background: var(--gray-light);
     border-radius: 3px;
     overflow: hidden;
     margin: 8px 0;
 }

 .progress-fill {
     height: 100%;
     background: var(--primary);
     border-radius: 3px;
     transition: width 0.3s ease;
 }

 /* Checklist item card */
 .checklist-card {
     background: var(--surface);
     border-radius: var(--radius);
     box-shadow: var(--shadow);
     padding: 20px;
     margin-bottom: 16px;
 }

 .checklist-category {
     font-size: 0.75rem;
     font-weight: 700;
     text-transform: uppercase;
     letter-spacing: 0.5px;
     color: var(--primary);
     margin-bottom: 4px;
 }

 .checklist-description {
     font-size: 1.05rem;
     font-weight: 500;
     color: var(--text);
     margin-bottom: 4px;
 }

 .checklist-counter {
     font-size: 0.8rem;
     color: var(--text-secondary);
     margin-bottom: 12px;
 }

 /* Photo grid */
 .photo-grid {
     display: grid;
     grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
     gap: 8px;
     margin-top: 12px;
 }

 .photo-thumb {
     aspect-ratio: 1;
     border-radius: 8px;
     overflow: hidden;
     position: relative;
 }

 .photo-thumb img {
     width: 100%;
     height: 100%;
     object-fit: cover;
 }

 .photo-capture-btn {
     display: flex;
     align-items: center;
     justify-content: center;
     min-height: 56px;
     background: var(--gray-light);
     border: 2px dashed var(--gray);
     border-radius: var(--radius);
     color: var(--gray);
     font-size: 0.9rem;
     font-weight: 600;
     cursor: pointer;
     gap: 8px;
     margin-top: 12px;
 }

 .photo-capture-btn:active {
     background: #e5e7eb;
 }

 /* Notes toggle */
 .notes-toggle {
     display: flex;
     align-items: center;
     gap: 6px;
     margin-top: 12px;
     padding: 8px 0;
     color: var(--text-secondary);
     font-size: 0.85rem;
     cursor: pointer;
     border: none;
     background: none;
     min-height: var(--touch-target);
 }

 /* Empty state */
 .empty-state {
     display: flex;
     flex-direction: column;
     align-items: center;
     justify-content: center;
     padding: 48px 24px;
     text-align: center;
 }

 .empty-icon {
     font-size: 3rem;
     margin-bottom: 16px;
 }

 .empty-title {
     font-size: 1.2rem;
     font-weight: 600;
     color: var(--text);
     margin-bottom: 8px;
 }

 .empty-subtitle {
     font-size: 0.9rem;
     color: var(--text-secondary);
     margin-bottom: 24px;
 }

 /* Page headers */
 .page-header {
     margin-bottom: 20px;
 }

 .page-title {
     font-size: 1.5rem;
     font-weight: 700;
     color: var(--text);
     margin: 0;
 }

 .page-subtitle {
     font-size: 0.9rem;
     color: var(--text-secondary);
     margin-top: 4px;
 }

 /* Navigation progress */
 .checklist-nav {
     display: flex;
     align-items: center;
     justify-content: space-between;
     margin-top: 16px;
     gap: 12px;
 }

 .checklist-nav .btn {
     flex: 1;
 }

 /* Inspection detail */
 .detail-section {
     margin-bottom: 24px;
 }

 .detail-label {
     font-size: 0.8rem;
     font-weight: 600;
     color: var(--text-secondary);
     text-transform: uppercase;
     letter-spacing: 0.5px;
 }

 .detail-value {
     font-size: 1rem;
     color: var(--text);
     margin-top: 2px;
 }

 .result-icon {
     display: inline-flex;
     align-items: center;
     justify-content: center;
     width: 28px;
     height: 28px;
     border-radius: 50%;
     font-size: 0.8rem;
     font-weight: 700;
     margin-right: 8px;
 }

 .result-icon.pass { background: var(--success-light); color: var(--success); }
 .result-icon.fail { background: var(--danger-light); color: var(--danger); }
 .result-icon.na { background: var(--gray-light); color: var(--gray); }
 .result-icon.unchecked { background: var(--gray-light); color: var(--gray); }

 /* Template selection */
 .template-card {
     background: var(--surface);
     border-radius: var(--radius);
     box-shadow: var(--shadow);
     padding: 16px;
     margin-bottom: 12px;
     cursor: pointer;
     border: 2px solid transparent;
     transition: border-color 0.15s, transform 0.1s;
 }

 .template-card:active {
     transform: scale(0.98);
 }

 .template-card.selected {
     border-color: var(--primary);
     background: #eff6ff;
 }

 .template-name {
     font-size: 1rem;
     font-weight: 600;
 }

 .template-desc {
     font-size: 0.85rem;
     color: var(--text-secondary);
     margin-top: 2px;
 }

 .template-count {
     font-size: 0.75rem;
     color: var(--primary);
     font-weight: 600;
     margin-top: 4px;
 }

 /* Blazor error UI */
 #blazor-error-ui {
     background: var(--danger);
     color: white;
     padding: 12px 24px;
     position: fixed;
     bottom: 0;
     left: 0;
     right: 0;
     z-index: 9999;
     display: none;
     text-align: center;
 }

 #blazor-error-ui .dismiss {
     cursor: pointer;
     margin-left: 16px;
 }

 /* Tablet and larger */
 @media (min-width: 768px) {
     .page-content {
         padding: 24px;
         padding-bottom: calc(var(--nav-height) + 32px);
     }

     .check-buttons {
         gap: 12px;
     }

     .check-btn {
         min-height: 64px;
         font-size: 1rem;
     }
 }

